return $input.all().map(item => {
  const root = item.json || {};
  const b = root.body || root;
  const data = b.data || {};
  const key = data.key || {};
  const remoteJid = String(key.remoteJid || '');
  const phoneRaw = remoteJid.split('@')[0];
  const phone = phoneRaw.replace(/\D/g, '');
  const msgTypeRaw = data.messageType || '';
  const messageType = msgTypeRaw === 'conversation' ? 'text'
                   : msgTypeRaw === 'audioMessage' ? 'audio'
                   : msgTypeRaw === 'imageMessage' ? 'image'
                   : msgTypeRaw === 'documentMessage' ? 'document'
                   : 'unknown';
  const msg = data.message || {};
  const text = msg.conversation || (msg.extendedTextMessage && msg.extendedTextMessage.text) || '';
  return {
    json: {
      instance: b.instance || null,
      phone,
      msgId: String(key.id || ''),
      fromMe: key.fromMe === true,
      messageType,
      text,
      chatwoot_conversation_id: data.chatwoot_conversation_id || null,
      chatwoot_inbox_id: data.chatwoot_inbox_id || null,
      test_run_id: b.test_run_id || null,
      _test_hour_override: b._test_hour_override
    }
  };
});

