// v1: per-workflow gate (settings.workflows_enabled.IGOR_01) deliberately
// NOT consulted — only ai_enabled_global kill-switch is honored. TODO v2:
// reintroduce per-workflow gate once /admin tooling toggles it safely.
const f = $('Extract Fields').first().json;
const s = $input.first().json || {};
const aiGlobal = s.ai_enabled_global !== false;
const hoursStart = s.hours_start || '18:30';
const hoursEnd = s.hours_end || '07:30';
const tz = s.tz || 'America/Sao_Paulo';

let hour = f._test_hour_override;
if (hour === undefined || hour === null) {
  const h = new Date().toLocaleString('en-US', { hour: '2-digit', hour12: false, timeZone: tz });
  hour = parseInt(h, 10);
}

const startH = parseInt(hoursStart.split(':')[0], 10);
const endH = parseInt(hoursEnd.split(':')[0], 10);
// After-hours: hour >= startH OR hour < endH
const isAfterHours = hour >= startH || hour < endH;

// Phone normalization: 55 + DDD (2) + 9 digits = 13 chars
const phoneValid = /^55\d{11}$/.test(f.phone);

let blocked = null;
if (!aiGlobal) blocked = 'ai_disabled_global';
else if (!phoneValid) blocked = 'invalid_phone';
else if (!isAfterHours) blocked = 'within_hours';

return [{
  json: {
    ...f,
    ai_enabled_global: aiGlobal,
    hours_start: hoursStart,
    hours_end: hoursEnd,
    tz,
    hour_evaluated: hour,
    is_after_hours: isAfterHours,
    phone_valid: phoneValid,
    blocked,
    current_flow: blocked ? null : 'after_hours',
    target_workflow: blocked ? null : 'IGOR_03'
  }
}];

