const f = $('Compute Routing').first().json;
const rows = $input.all();
let convBlocked = false;
let humanLocked = false;
let aiEnabled = true;
if (rows.length > 0 && rows[0].json) {
  const r = rows[0].json;
  humanLocked = r.human_locked === true;
  aiEnabled = r.ai_enabled !== false;
  convBlocked = humanLocked || !aiEnabled;
}
return [{
  json: {
    ...f,
    conversation_human_locked: humanLocked,
    conversation_ai_enabled: aiEnabled,
    conversation_blocked: convBlocked
  }
}];

